import { NextRequest, NextResponse } from "next/server";
import prisma from "@/lib/db";
import { sendLocksmithVerifiedEmail } from "@/lib/email";
import { isInUkOrIreland } from "@/lib/geo-guard";
import {
  extractUkPostcode,
  isCoordinatePair,
  normalizeUkPostcode,
  reverseGeocodePostcodeFromCoords,
} from "@/lib/location-display";
import { deleteLocksmithCascade } from "@/lib/locksmith-deletion";
import { verifyProfilePhoto } from "@/lib/credential-verifier";

// GET /api/locksmiths/[id] - Get locksmith public profile with reviews
export async function GET(
  request: NextRequest,
  { params }: { params: Promise<{ id: string }> }
) {
  try {
    const { id } = await params;

    // Validate MongoDB ObjectId format before querying
    if (!/^[0-9a-fA-F]{24}$/.test(id)) {
      return NextResponse.json(
        { success: false, error: "Locksmith not found" },
        { status: 404 }
      );
    }

    const locksmith = await prisma.locksmith.findUnique({
      where: { id },
      select: {
        id: true,
        name: true,
        companyName: true,
        profileImage: true,
        rating: true,
        totalJobs: true,
        isVerified: true,
        yearsExperience: true,
        services: true,
        coverageAreas: true,
        createdAt: true,
        reviews: {
          where: { isPublic: true },
          select: {
            id: true,
            rating: true,
            comment: true,
            createdAt: true,
            customer: {
              select: {
                name: true,
              },
            },
            job: {
              select: {
                jobNumber: true,
                problemType: true,
                postcode: true,
              },
            },
          },
          orderBy: { createdAt: "desc" },
          take: 50,
        },
        _count: {
          select: {
            reviews: true,
          },
        },
      },
    });

    if (!locksmith) {
      return NextResponse.json(
        { success: false, error: "Locksmith not found" },
        { status: 404 }
      );
    }

    // Calculate rating breakdown
    const allReviews = await prisma.review.findMany({
      where: { locksmithId: id, isPublic: true },
      select: { rating: true },
    });

    const ratingBreakdown = {
      5: 0,
      4: 0,
      3: 0,
      2: 0,
      1: 0,
    };

    for (const review of allReviews) {
      if (review.rating >= 1 && review.rating <= 5) {
        ratingBreakdown[review.rating as keyof typeof ratingBreakdown]++;
      }
    }

    // Get response time stats (average ETA from accepted applications)
    const applications = await prisma.locksmithApplication.findMany({
      where: {
        locksmithId: id,
        status: "accepted",
      },
      select: {
        eta: true,
      },
    });

    const avgResponseTime = applications.length > 0
      ? Math.round(applications.reduce((acc, app) => acc + app.eta, 0) / applications.length)
      : 30;

    // Format response
    const profile = {
      id: locksmith.id,
      name: locksmith.name,
      company: locksmith.companyName,
      avatar: locksmith.profileImage || locksmith.name.split(" ").map(n => n[0]).join("").toUpperCase().slice(0, 2),
      rating: locksmith.rating,
      reviewCount: locksmith._count.reviews,
      totalJobs: locksmith.totalJobs,
      verified: locksmith.isVerified,
      yearsExperience: locksmith.yearsExperience,
      services: locksmith.services,
      coverageAreas: locksmith.coverageAreas.slice(0, 10), // First 10 postcodes
      memberSince: locksmith.createdAt,
      avgResponseTime,
      ratingBreakdown,
      reviews: locksmith.reviews.map(review => ({
        id: review.id,
        rating: review.rating,
        comment: review.comment,
        createdAt: review.createdAt,
        customerName: review.customer.name,
        jobType: review.job.problemType,
        location: review.job.postcode.split(" ")[0], // First part of postcode
      })),
    };

    return NextResponse.json({
      success: true,
      profile,
    });
  } catch (error) {
    console.error("Error fetching locksmith profile:", error);
    return NextResponse.json(
      { success: false, error: "Failed to fetch profile" },
      { status: 500 }
    );
  }
}

// PATCH /api/locksmiths/[id] - Update locksmith (admin actions)
export async function PATCH(
  request: NextRequest,
  { params }: { params: Promise<{ id: string }> }
) {
  try {
    const { id } = await params;
    const body = await request.json();
    const { action, ...updateData } = body;

    // Find the locksmith
    const locksmith = await prisma.locksmith.findUnique({
      where: { id },
    });

    if (!locksmith) {
      return NextResponse.json(
        { success: false, error: "Locksmith not found" },
        { status: 404 }
      );
    }

    // Handle different admin actions
    if (action === "verify") {
      const updated = await prisma.locksmith.update({
        where: { id },
        data: { isVerified: true },
      });

      // Send verification email to locksmith (non-blocking)
      sendLocksmithVerifiedEmail(updated.email, {
        locksmithName: updated.name,
        companyName: updated.companyName,
      }).catch((err) => {
        console.error("Failed to send verification email:", err);
      });

      return NextResponse.json({
        success: true,
        message: "Locksmith verified successfully",
        locksmith: {
          id: updated.id,
          name: updated.name,
          isVerified: updated.isVerified,
        },
      });
    }

    if (action === "unverify") {
      const updated = await prisma.locksmith.update({
        where: { id },
        data: { isVerified: false },
      });

      return NextResponse.json({
        success: true,
        message: "Locksmith verification removed",
        locksmith: {
          id: updated.id,
          name: updated.name,
          isVerified: updated.isVerified,
        },
      });
    }

    if (action === "suspend") {
      const updated = await prisma.locksmith.update({
        where: { id },
        data: { isActive: false },
      });

      return NextResponse.json({
        success: true,
        message: "Locksmith suspended",
        locksmith: {
          id: updated.id,
          name: updated.name,
          isActive: updated.isActive,
        },
      });
    }

    if (action === "activate") {
      const updated = await prisma.locksmith.update({
        where: { id },
        data: { isActive: true },
      });

      return NextResponse.json({
        success: true,
        message: "Locksmith activated",
        locksmith: {
          id: updated.id,
          name: updated.name,
          isActive: updated.isActive,
        },
      });
    }

    // General update (for other fields)
    const allowedFields = ['name', 'companyName', 'phone', 'email', 'yearsExperience', 'coverageAreas', 'services', 'profileImage', 'coverageRadius', 'baseAddress', 'baseLat', 'baseLng', 'profilePhotoVerified', 'profilePhotoRejectionReason'];
    const filteredData: Record<string, unknown> = {};

    for (const field of allowedFields) {
      if (updateData[field] !== undefined) {
        filteredData[field] = updateData[field];
      }
    }

    // If admin is manually setting profilePhotoVerified, stamp the timestamp
    if (filteredData.profilePhotoVerified === true) {
      filteredData.profilePhotoVerifiedAt = new Date();
      filteredData.profilePhotoRejectionReason = null;
    } else if (filteredData.profilePhotoVerified === false) {
      filteredData.profilePhotoVerifiedAt = null;
    }

    // If base location is being changed, enforce UK + Ireland restriction
    if (filteredData.baseLat !== undefined || filteredData.baseLng !== undefined) {
      const newLat = Number(filteredData.baseLat ?? updateData.baseLat);
      const newLng = Number(filteredData.baseLng ?? updateData.baseLng);
      if (Number.isFinite(newLat) && Number.isFinite(newLng)) {
        const geoCheck = await isInUkOrIreland(newLat, newLng);
        if (!geoCheck.ok) {
          return NextResponse.json(
            { success: false, error: geoCheck.reason ?? "Location not supported" },
            { status: 400 }
          );
        }
      }
    }

    if (filteredData.baseAddress !== undefined || filteredData.baseLat !== undefined || filteredData.baseLng !== undefined) {
      const rawBaseAddress = typeof filteredData.baseAddress === "string"
        ? filteredData.baseAddress
        : typeof updateData.baseAddress === "string"
          ? updateData.baseAddress
          : "";

      const lat = Number(filteredData.baseLat ?? updateData.baseLat ?? locksmith.baseLat);
      const lng = Number(filteredData.baseLng ?? updateData.baseLng ?? locksmith.baseLng);

      const extractedPostcode = normalizeUkPostcode(rawBaseAddress) ?? extractUkPostcode(rawBaseAddress);
      const reversePostcode = extractedPostcode
        ? extractedPostcode
        : await reverseGeocodePostcodeFromCoords(lat, lng);

      filteredData.baseAddress = reversePostcode ?? null;
    }

    if (Object.keys(filteredData).length > 0) {
      const updated = await prisma.locksmith.update({
        where: { id },
        data: filteredData,
      });

      // If profileImage changed, kick off async AI face verification
      if (typeof filteredData.profileImage === "string" && filteredData.profileImage.length > 0) {
        const newPhotoUrl = filteredData.profileImage;
        prisma.locksmith
          .update({
            where: { id },
            data: {
              profilePhotoVerified: false,
              profilePhotoVerifiedAt: null,
              profilePhotoRejectionReason: null,
              profilePhotoAiConfidence: null,
            },
          })
          .catch((err) => console.error("[AdminLocksmithPatch] reset face flags failed:", err));

        verifyProfilePhoto(newPhotoUrl, updated.name)
          .then((result) =>
            prisma.locksmith.update({
              where: { id },
              data: {
                profilePhotoVerified: result.isRealFace,
                profilePhotoVerifiedAt: result.isRealFace ? new Date() : null,
                profilePhotoRejectionReason: result.rejectionReason ?? null,
                profilePhotoAiConfidence: result.confidence,
              },
            })
          )
          .catch((err) => console.error("[AdminLocksmithPatch] face verify failed:", err));
      }

      return NextResponse.json({
        success: true,
        message: "Locksmith updated successfully",
        locksmith: updated,
      });
    }

    return NextResponse.json(
      { success: false, error: "No valid action or update data provided" },
      { status: 400 }
    );
  } catch (error) {
    console.error("Error updating locksmith:", error);
    return NextResponse.json(
      { success: false, error: "Failed to update locksmith" },
      { status: 500 }
    );
  }
}

// DELETE /api/locksmiths/[id] - Delete a locksmith (admin only)
export async function DELETE(
  request: NextRequest,
  { params }: { params: Promise<{ id: string }> }
) {
  try {
    const { id } = await params;

    const deletion = await deleteLocksmithCascade(id);

    console.log(`[Admin Delete Locksmith] Successfully deleted locksmith ${deletion.locksmithName} and ${deletion.deletedJobCount} associated job(s)`, deletion.relatedCounts);

    return NextResponse.json({
      success: true,
      message: `Locksmith "${deletion.locksmithName}" and ${deletion.deletedJobCount} associated job(s) deleted successfully`,
      deletedJobs: deletion.deletedJobNumbers,
    });
  } catch (error: any) {
    if (error instanceof Error && error.message === "LOCKSMITH_NOT_FOUND") {
      return NextResponse.json(
        { success: false, error: "Locksmith not found" },
        { status: 404 }
      );
    }
    console.error("Error deleting locksmith:", {
      message: error?.message,
      code: error?.code,
      meta: error?.meta,
    });
    return NextResponse.json(
      {
        success: false,
        error: "Failed to delete locksmith",
        ...(error?.code ? { code: error.code } : {}),
        ...(process.env.NODE_ENV !== "production"
          ? {
              detail: error?.message,
            }
          : {}),
      },
      { status: 500 }
    );
  }
}
